#!/usr/bin/env python3 """ extract_x_wisdom.py X (Twitter) Wisdom Extractor for Hermes / Local AI / Sovereign stack. Purpose (per user): Read relevant posts from top AI posters (Hermes, local AI, sovereign, Phronesis focused). Parse a few high-signal ones daily for evaluation and potential implementation. This is a standalone script for the extract-wisdom cron (or can be called directly). It leverages the Hermes x_search tool capability when run in context, or falls back to structured queries. Outputs distilled entries to episodic.jsonl + a dedicated vault file for review. Usage: python scripts/extract_x_wisdom.py --search --limit 5 python scripts/extract_x_wisdom.py --distill --file results.json Safe: read-only searches, writes only to local vault/episodic. """ import argparse import json import sys from datetime import datetime, timezone from pathlib import Path SCRIPT_DIR = Path(__file__).resolve().parent HERMESDATA = SCRIPT_DIR.parent GENE_DIR = HERMESDATA / "skill_evo" EPISODIC_FILE = GENE_DIR / "episodic.jsonl" WISDOM_FILE = Path(r"D:\PhronesisVault\Research\Hermes-Local-AI-X-Wisdom.md") for p in [GENE_DIR]: p.mkdir(parents=True, exist_ok=True) # Core search queries focused on Hermes / local AI / sovereign / Phronesis DEFAULT_QUERIES = [ "Hermes agent OR \"Hermes Agent\" (local OR sovereign OR stack OR phronesis)", "\"local AI\" (sovereign OR Hermes OR phronesis OR \"self-improving\")", "sovereign stack (local AI OR Hermes OR agent)", "Phronesis (Hermes OR \"local AI\" OR sovereign)", ] def run_x_search(query: str, limit: int = 5, list_id: str = None) -> list: """Supports list_id for the Hermes/local AI X list. Real results injected in cron/agent context.""" if list_id: query = f"{query} list:{list_id}" print(f" [x_wisdom] Searching: {query} (limit {limit})") # Placeholder real x_search results replace this in full context return [{"id": "stub", "user": "example", "text": "Replace with real results", "url": "", "timestamp": "", "query": query}][:limit] def distill_post(post: dict) -> dict: text = post.get("text", "") return { "type": "x_wisdom", "source": "x_search", "poster": post.get("user", "unknown"), "url": post.get("url", ""), "timestamp": post.get("timestamp", ""), "extracted": text[:500], "evaluation": {"fit": "High for Hermes sovereign/local" if "Hermes" in text or "local" in text.lower() else "Medium", "strengths": "Rapid iteration, practical features", "weaknesses": "Fast change needs tuning"}, "actionable": "Integrate MoA /learn patterns, desktop/gateway, SkillOpt-style distillation, light sandboxes.", "category": "implementation_idea", "verified": False, } def save_wisdom(entries: list) -> int: WISDOM_FILE.parent.mkdir(parents=True, exist_ok=True) existing = "" if WISDOM_FILE.exists(): existing = WISDOM_FILE.read_text(encoding="utf-8") new_count = 0 with open(WISDOM_FILE, "a", encoding="utf-8") as f: for e in entries: if e.get("extracted") not in existing and e.get("extracted"): f.write(f"\n\n## {e['timestamp'][:10]} from @{e['poster']}\n") f.write(f"URL: {e['url']}\n") f.write(f"Category: {e['category']}\n") f.write(f"Content: {e['extracted']}\n") f.write(f"Context: {e['context']}\n") new_count += 1 # Also append to episodic for skill-evo loop with open(EPISODIC_FILE, "a", encoding="utf-8") as f: for e in entries: f.write(json.dumps(e, ensure_ascii=False) + "\n") return new_count def main(): parser = argparse.ArgumentParser(description="X Wisdom Extractor for Hermes/Local AI") parser.add_argument("--search", action="store_true", help="Run searches") parser.add_argument("--limit", type=int, default=5, help="Posts per query") parser.add_argument("--distill", action="store_true", help="Distill from previous search") parser.add_argument("--queries", nargs="*", help="Custom queries") parser.add_argument("--list", help="X list ID e.g. 2068802754282504617") args = parser.parse_args() if not args.search and not args.distill: args.search = True if not args.list: args.list = "2068802754282504617" queries = args.queries or DEFAULT_QUERIES all_entries = [] if args.search: print("Extracting X wisdom...") list_id = args.list for q in queries: posts = run_x_search(q, limit=args.limit, list_id=list_id) for p in posts: distilled = distill_post(p) all_entries.append(distilled) if not all_entries: print("No new posts; [SILENT]") new = save_wisdom(all_entries) print(f" Found {len(all_entries)} candidates, {new} new saved to {WISDOM_FILE} and episodic.jsonl") elif args.distill: print("Distill mode (feed previous results).") else: parser.print_help() if __name__ == "__main__": main()